        #region 高跳
        private static Entity? FindHighJumpSmashTargetEntity(Entity entity)
        {
            bool haveBeenPricked = HaveBeenPricked(entity);

            IEnumerable<Entity> validEntities;
            highJumpSearchBuffer.Clear();
            if (!haveBeenPricked)
            {
                entity.Level.FindEntitiesNonAlloc(e => entity.IsHostile(e) && e.IsVulnerableEntity() && !e.IsInvincible(), highJumpSearchBuffer);
                validEntities = highJumpSearchBuffer.Where(e => e.IsEntityOf(VanillaContraptionID.amethystPylon));
                if (validEntities.Count() <= 0)
                {
                    validEntities = highJumpSearchBuffer;
                }
            }
            else
            {
                entity.Level.FindEntitiesNonAlloc(e => entity.IsHostile(e) && e.IsVulnerableEntity() && !e.IsInvincible() && !e.IsEntityOf(VanillaContraptionID.amethystPylon), highJumpSearchBuffer);
                validEntities = highJumpSearchBuffer;
            }
            if (validEntities.Count() <= 0)
                return null;
            return validEntities.Random(entity.RNG);
        }
        private static Vector3 FindHighJumpSmashTarget(Entity entity)
        {
            var target = FindHighJumpSmashTargetEntity(entity);
            Vector3 position;
            if (target == null)
            {
                position = entity.Position;
            }
            else
            {
                position = target.Position;
            }
            position.y = entity.Level.GetGroundY(position.x, position.z);
            return position;
        }
        public static void PrickHighJump(Entity entity, Entity source)
        {
            if (stateMachine.GetStateNumber(entity) != STATE_SMASH)
                return;
            entity.TakeDamage(600, new DamageEffectList(VanillaDamageEffects.SLICE), source);
            stateMachine.StartSubState(entity, HighJumpState.SUBSTATE_PRICKED);
            SetHaveBeenPricked(entity, true);
            var timer = stateMachine.GetSubStateTimer(entity);
            timer.ResetSeconds(1);
            SetShake(entity, true);

            RemoveSmashTarget(entity);

            var pos = entity.Position;
            var vel = entity.Velocity;
            pos.y = source.GetBounds().max.y;
            vel.y = 0;
            entity.Position = pos;
            entity.Velocity = vel;
            entity.Spawn(VanillaEffectID.stabEffect, (entity.Position + source.Position) / 2);
            entity.SetProperty(PROP_GRAVITY_MULTIPLIER, 0f);

            entity.PlaySound(VanillaSoundID.shieldHit);
            entity.PlaySound(VanillaSoundID.lockedChestOuch);
        }
        private class HighJumpState : EntityStateMachineState
        {
            public HighJumpState() : base(STATE_SMASH, ANIMATION_STATE_SMASH) { }
            public override int GetAnimationState(int substate)
            {
                if (substate == SUBSTATE_SHAKE)
                {
                    return ANIMATION_STATE_IDLE;
                }
                return base.GetAnimationState(substate);
            }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_FALL || substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_SMASH_FALL;
                }
                return ANIMATION_SUBSTATE_SMASH_JUMP;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1);
                SetShake(entity, true);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                SetShake(entity, false);

                RemoveSmashTarget(entity);
                entity.SetProperty(PROP_GRAVITY_MULTIPLIER, 1f);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_SHAKE:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_JUMP);
                            timer.ResetSeconds(1);
                            SetShake(entity, false);
                            var position = FindHighJumpSmashTarget(entity);
                            SetTargetPosition(entity, position);
                            SpawnSmashTarget(entity, position);

                            entity.PlaySound(VanillaSoundID.launch);
                        }
                        break;
                    case SUBSTATE_JUMP:
                        {
                            entity.Velocity = Vector3.up * 100;
                            SpawnShadow(entity);
                            if (timer.Expired)
                            {
                                stateMachine.StartSubState(entity, SUBSTATE_FALL);
                            }
                        }
                        break;
                    case SUBSTATE_FALL:
                        {
                            var targetPosition = GetTargetPosition(entity);
                            var velocity = (targetPosition - entity.Position) * 0.8f;
                            velocity.y = -50;
                            entity.Velocity = velocity;

                            SpawnShadow(entity, true);
                            if (entity.IsOnGround)
                            {
                                float damage = entity.GetDamage() * SMASH_DAMAGE_MULTIPLIER;
                                HighJumpSmash(entity, damage);

                                stateMachine.StartSubState(entity, SUBSTATE_END);
                                timer.ResetSeconds(1);

                                RemoveSmashTarget(entity);
                                entity.PlaySound(VanillaSoundID.smash);
                                entity.Level.ShakeScreen(10, 0, 15);
                            }
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                    case SUBSTATE_PRICKED:
                        entity.Velocity = Vector3.zero;
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public static void HighJumpSmash(Entity entity, float damage)
            {
                highJumpDamageBuffer.Clear();
                highJumpDetector.DetectMultiple(entity, highJumpDamageBuffer);
                foreach (var target in highJumpDamageBuffer)
                {
                    target.TakeDamage(damage, new DamageEffectList(VanillaDamageEffects.EXPLOSION, VanillaDamageEffects.IGNORE_ARMOR), entity);
                }
            }
            public const int SUBSTATE_SHAKE = 0;
            public const int SUBSTATE_JUMP = 1;
            public const int SUBSTATE_FALL = 2;
            public const int SUBSTATE_END = 3;
            public const int SUBSTATE_PRICKED = 4;
        }
        #endregion

        #region 封锁
        private static bool CanSwitchToLockState(Entity entity)
        {
            var level = entity.Level;
            var seedPacks = GetBlueprintsToLock(level);
            if (seedPacks.Count() <= 0)
                return false;
            return true;
        }
        public static IEnumerable<SeedPack> GetBlueprintsToLock(LevelEngine level)
        {
            if (level.IsConveyorMode())
            {
                return level.GetAllConveyorSeedPacks();
            }
            else
            {
                return level.GetAllSeedPacks().OfType<SeedPack>();
            }
        }
        public static void LockRandomBlueprint(Entity entity, int count)
        {
            var level = entity.Level;
            var seedPacks = GetBlueprintsToLock(level);
            if (seedPacks.Count() <= 0)
                return;
            var selected = seedPacks.RandomTake(count, entity.RNG);
            if (selected == null)
                return;
            foreach (var seedPack in selected)
            {
                seedPack.AddBuff<BlueprintLockBuff>();
            }
        }
        private class LockState : EntityStateMachineState
        {
            public LockState() : base(STATE_LOCK, ANIMATION_STATE_IDLE) { }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1);
                SetShake(entity, true);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                SetShake(entity, false);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_SHAKE:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_LOCK);
                            timer.ResetSeconds(1);

                            LockRandomBlueprint(entity, 1);
                            entity.Spawn(VanillaEffectID.lockSigil, entity.GetCenter());

                            entity.Level.ShakeScreen(10, 0, 15);
                            entity.PlaySound(VanillaSoundID.locked);
                            SetShake(entity, false);
                        }
                        break;
                    case SUBSTATE_LOCK:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public const int SUBSTATE_SHAKE = 0;
            public const int SUBSTATE_LOCK = 1;
        }
        #endregion

        #region 粉碎之锁
        private static bool CanSwitchToCrushingLockState(Entity entity)
        {
            return FindCrushingLockTargetGridIndexes(entity).Count() >= 0 && GetPossibleRequiredContraptionID(entity.Level).Count() > 0;
        }
        public static IEnumerable<int> FindCrushingLockTargetGridIndexes(Entity entity)
        {
            var level = entity.Level;
            int columnCount = level.GetMaxColumnCount();
            int laneCount = level.GetMaxLaneCount();
            int maxIndex = columnCount * laneCount;

            // 使用数组代替字典，内存连续、访问更快（索引范围已知）
            var contraptions = new bool[maxIndex];
            var neighborCounts = new int[maxIndex];

            // 先记录所有植物的位置
            foreach (var contraption in level.FindEntities(e => e.Type == EntityTypes.PLANT))
            {
                int idx = contraption.GetGridIndex();
                if ((uint)idx < (uint)maxIndex)   // 边界检查的惯用高效写法
                    contraptions[idx] = true;
            }

            // 统计每个格子周围 8 格的植物数量
            for (int idx = 0; idx < maxIndex; idx++)
            {
                if (!contraptions[idx])
                    continue;

                int x = level.GetGridColumnByIndex(idx);
                int y = level.GetGridLaneByIndex(idx);

                int count = 0;
                for (int dx = -1; dx <= 1; dx++)
                {
                    int nx = x + dx;
                    if ((uint)nx >= (uint)columnCount)
                        continue;
                    for (int dy = -1; dy <= 1; dy++)
                    {
                        if (dx == 0 && dy == 0)
                            continue;
                        int ny = y + dy;
                        if ((uint)ny >= (uint)laneCount)
                            continue;
                        int neighborIdx = ny * columnCount + nx; // 直接计算，避免方法调用
                                                                 // 相邻格子只要有植物（或未来可能有机关）就算一次
                                                                 // 此处简单起见，有植物就算一次“包围”
                        if (contraptions[neighborIdx])
                            count++;
                    }
                }
                neighborCounts[idx] = count;
            }

            // 找出存活植物中 neighborCounts 最大的那个
            return neighborCounts.GetMostOnes(c => c);
        }
        public static IEnumerable<SeedPack> GetPossibleRequiredContraptionID(LevelEngine level)
        {
            IEnumerable<SeedPack> seedPacks;
            if (level.IsConveyorMode())
            {
                seedPacks = level.GetAllConveyorSeedPacks();
            }
            else
            {
                seedPacks = level.GetAllSeedPacks().OfType<SeedPack>();
            }
            return seedPacks.Where(s =>
            {
                if (s.IsUpgradeBlueprint() || s.CanInstantTrigger() || s.GetSeedType() != SeedTypes.ENTITY)
                    return false;
                var entityID = s.GetSeedEntityID();
                var entityDef = level.Content.GetEntityDefinition(entityID);
                if (entityDef == null)
                    return false;
                var gridLayers = entityDef.GetGridLayersToTake();
                if (gridLayers == null || !gridLayers.Contains(VanillaGridLayers.main))
                    return false;
                return true;
            });
        }
        public static NamespaceID? GetRandomRequiredContraptionID(LevelEngine level, RandomGenerator rng)
        {
            var validSeedPacks = GetPossibleRequiredContraptionID(level);
            if (validSeedPacks.Count() <= 0)
                return null;
            return validSeedPacks.Random(rng).GetSeedEntityID();
        }
        public static void CrushingLock(Entity entity)
        {
            var gridIndexes = FindCrushingLockTargetGridIndexes(entity);
            if (gridIndexes.Count() < 0)
                return;
            var rng = entity.RNG;
            var gridIndex = gridIndexes.Random(rng);
            var grid = entity.Level.GetGrid(gridIndex);
            if (grid == null)
                return;
            var damageEffects = new DamageEffectList(VanillaDamageEffects.INSTA_KILL);
            foreach (var ent in grid.GetEntities())
            {
                ent.Die(damageEffects, entity);
            }
            var requiredID = GetRandomRequiredContraptionID(entity.Level, rng);
            if (requiredID != null)
            {
                PsychicShackle.Spawn(entity.Level, grid.GetEntityPosition(), requiredID, entity);
            }
        }
        private class CrushingLockState : EntityStateMachineState
        {
            public CrushingLockState() : base(STATE_CRUSHING_LOCK, ANIMATION_STATE_IDLE) { }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
